module top_module (
    input z,
    input x,
    input j,
    input l,
    output reg obf_g
);
    always @(*) begin
        case ({z, x, j, l})
            4'b0000: obf_g = 1'b1;
            4'b0011: obf_g = 1'b0;
            4'b1101: obf_g = 1'b1;
            4'b1110: obf_g = 1'b1;
            4'b0111: obf_g = 1'b0;
            4'b1010: obf_g = 1'b1;
            4'b0101: obf_g = 1'b1;
            4'b0001: obf_g = 1'b1;
            4'b0110: obf_g = 1'b0;
            4'b1001: obf_g = 1'b0;
            4'b1111: obf_g = 1'b1;
            4'b0100: obf_g = 1'b1;
            4'b1011: obf_g = 1'b1;
            4'b0010: obf_g = 1'b1;
            4'b1000: obf_g = 1'b1;
            4'b1100: obf_g = 1'b0;
        endcase
    end
endmodule
